// Take first 5 story IDs
const storyIds = $input.first().json;
const top5 = storyIds.slice(0, 5);
return top5.map(id => ({ json: { storyId: id } }));

// Collect all HN stories into one item
const stories = $input.all().map(item => ({
  title: item.json.title,
  url: item.json.url || `https://news.ycombinator.com/item?id=${item.json.id}`,
  score: item.json.score,
  by: item.json.by
}));
return [{ json: { stories } }];

// Merge all upstream data into a single prompt
const crypto = $('Get Crypto Prices').first().json;
const exchange = $('Get ILS/USD Rate').first().json;
const weather = $('Get Tel Aviv Weather').first().json;
const hnStories = $('Aggregate HN Stories').first().json.stories;

const ilsRate = exchange.rates ? exchange.rates.ILS : 'N/A';

const btcUsd = crypto.bitcoin?.usd || 'N/A';
const btcIls = crypto.bitcoin?.ils || 'N/A';
const btcChange = crypto.bitcoin?.usd_24h_change?.toFixed(2) || 'N/A';
const ethUsd = crypto.ethereum?.usd || 'N/A';
const ethIls = crypto.ethereum?.ils || 'N/A';
const ethChange = crypto.ethereum?.usd_24h_change?.toFixed(2) || 'N/A';

const tempMax = weather.daily?.temperature_2m_max?.[0] || 'N/A';
const tempMin = weather.daily?.temperature_2m_min?.[0] || 'N/A';
const rainChance = weather.daily?.precipitation_probability_max?.[0] || 'N/A';

const hnText = hnStories.map((s, i) => `${i+1}. ${s.title} (score: ${s.score}) - ${s.url}`).join('\n');

const prompt = `Create a concise, well-formatted morning briefing email for Nadav, an AI-focused digital agency owner in Tel Aviv, Israel. Today's date: ${new Date().toISOString().split('T')[0]}.

DATA:

**Crypto:**
- BTC: $${btcUsd} / ${btcIls} ILS (24h: ${btcChange}%)
- ETH: $${ethUsd} / ${ethIls} ILS (24h: ${ethChange}%)

**USD/ILS Rate:** ${ilsRate}

**Tel Aviv Weather:**
- High: ${tempMax}C, Low: ${tempMin}C
- Rain probability: ${rainChance}%

**Top Hacker News:**
${hnText}

Format as a clean HTML email with sections. Use a professional but friendly tone. Add a one-line AI industry insight or tip at the end. Subject line should be catchy.`;

return [{ json: { prompt, subject: `Morning Brief - ${new Date().toISOString().split('T')[0]}` } }];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || 'No summary generated';
const subject = $('Build AI Prompt').first().json.subject;

// Extract subject from AI response if it contains one
let emailSubject = subject;
const subjectMatch = content.match(/Subject:\s*(.+)/i);
if (subjectMatch) {
  emailSubject = subjectMatch[1].trim();
}

return [{ json: { emailBody: content, subject: emailSubject } }];
